when.set-body:
@{
          var outData = new JArray();
          var nowEpoch = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
          var sentinel = (string)context.Variables["autoSentinel"];
          var mini = (string)context.Variables["autoMini"];
          var full = (string)context.Variables["autoFull"];
          if (!string.IsNullOrWhiteSpace(sentinel) && !string.IsNullOrWhiteSpace(mini) && !string.IsNullOrWhiteSpace(full)) {
            var first = sentinel.Split(',')[0].Trim();
            if (first.Length > 0) {
              outData.Add(new JObject(new JProperty("id", first), new JProperty("object","model"), new JProperty("created",nowEpoch), new JProperty("owned_by","azure")));
            }
          }
          try {
            var src = context.Response.Body.As<JObject>(preserveContent: true);
            var arr = src["data"] as JArray;
            if (arr != null) {
              foreach (var d in arr) {
                var id = (string)d["id"];
                var status = (string)d["status"];
                if (!string.IsNullOrEmpty(id) && (status == null || status == "succeeded")) {
                  outData.Add(new JObject(new JProperty("id",id), new JProperty("object","model"), new JProperty("created",nowEpoch), new JProperty("owned_by","azure")));
                }
              }
            }
          } catch (Exception) { }
          return new JObject(new JProperty("object","list"), new JProperty("data",outData)).ToString(Newtonsoft.Json.Formatting.None);
        }
